from pathlib import Path
from datetime import date, datetime, timedelta
import csv
import re

log_dir = Path('/app/logs')
out_path = Path('/app/summary.csv')
ref = date(2025, 8, 12)
periods = [
    ('today', ref, ref),
    ('last_7_days', ref - timedelta(days=6), ref),
    ('last_30_days', ref - timedelta(days=29), ref),
    ('month_to_date', ref.replace(day=1), ref),
]
severities = ['ERROR', 'WARNING', 'INFO']
counts = {p: {s: 0 for s in severities} for p, *_ in periods}
counts['total'] = {s: 0 for s in severities}
pattern = re.compile(r'\[(ERROR|WARNING|INFO)\]')

for path in sorted(log_dir.glob('*.log')):
    try:
        file_date = datetime.strptime(path.name.split('_', 1)[0], '%Y-%m-%d').date()
    except ValueError:
        continue
    period_names = [name for name, start, end in periods if start <= file_date <= end]
    with path.open('r', encoding='utf-8') as f:
        for line in f:
            for sev in pattern.findall(line):
                counts['total'][sev] += 1
                for period_name in period_names:
                    counts[period_name][sev] += 1

with out_path.open('w', newline='', encoding='utf-8') as f:
    writer = csv.writer(f)
    writer.writerow(['period', 'severity', 'count'])
    for period in ['today', 'last_7_days', 'last_30_days', 'month_to_date', 'total']:
        for sev in severities:
            writer.writerow([period, sev, counts[period][sev]])
